/bin/zsh -lc "python - <<'PY'
import ast, csv, json
from pathlib import Path

ROOMS = {
    \"R01\": {\"capacity\": 10, \"equipment\": {\"projector\", \"whiteboard\"}},
    \"R02\": {\"capacity\": 20, \"equipment\": {\"projector\", \"whiteboard\", \"video_conf\"}},
    \"R03\": {\"capacity\": 6,  \"equipment\": {\"whiteboard\"}},
}
EXISTING = [
    {\"room\": \"R01\", \"date\": \"2024-03-15\", \"start\": \"09:00\", \"end\": \"11:00\", \"role\": \"manager\", \"recurring\": False},
    {\"room\": \"R02\", \"date\": \"2024-03-16\", \"start\": \"13:00\", \"end\": \"15:00\", \"role\": \"staff\", \"recurring\": True},
]
PRIORITY = {\"board\": 4, \"dept_head\": 3, \"manager\": 2, \"staff\": 1}

def to_min(t):
    h, m = t.split(':')
    return int(h) * 60 + int(m)

def overlaps(s1, e1, s2, e2):
    return s1 < e2 and s2 < e1

def evaluate(b):
    room = ROOMS[b['room']]
    if b['attendees'] > room['capacity']:
        return {\"result\": \"REJECTED\", \"reason\": \"capacity_exceeded\"}
    s, e = to_min(b['start']), to_min(b['end'])
    dur = e - s
    if s < 480 or e > 1200 or dur < 30 or dur > 240:
        return {\"result\": \"REJECTED\", \"reason\": \"time_invalid\"}
    if not set(b['required_equipment']).issubset(room['equipment']):
        return {\"result\": \"REJECTED\", \"reason\": \"equipment_missing\"}
    for ex in EXISTING:
        if ex['room'] == b['room'] and ex['date'] == b['date'] and overlaps(s, e, to_min(ex['start']), to_min(ex['end'])):
            bp, ep = PRIORITY[b['role']], PRIORITY[ex['role']]
            if bp > ep:
                continue
            if bp == ep and b['recurring'] and not ex['recurring']:
                continue
            return {\"result\": \"REJECTED\", \"reason\": \"conflict\"}
    return {\"result\": \"APPROVED\", \"reason\": \"\"}

actual = json.loads(Path('output.json').read_text())
expected = []
with open('input.csv', newline='') as f:
    for row in csv.DictReader(f):
        booking = {
            'room': row['room'],
            'attendees': int(row['attendees']),
            'date': row['date'],
            'start': row['start'],
            'end': row['end'],
            'required_equipment': ast.literal_eval(row['required_equipment']),
            'role': row['role'],
            'recurring': row['recurring'] == 'True',
        }
        expected.append({'id': row['id'], **evaluate(booking)})

assert actual == expected, (actual, expected)
print('JSON valid; output matches rule evaluation for', len(actual), 'requests')
PY"

